const toFormUrlEncoded = (params: Record<string, string>) =>
  new URLSearchParams(params).toString();

const handleCreatePaymentIntent = async (request: Request, env: Env) => {
  requireAuth(request, env);

  const body = await parseJsonBody<CreatePaymentIntentBody>(request);
  const { amount, currency, description, metadata, receipt_email } = body;

  if (!Number.isInteger(amount) || amount <= 0) {
    throw new HttpError(400, "Field 'amount' must be a positive integer in the smallest currency unit");
  }
  if (!currency || typeof currency !== "string") {
    throw new HttpError(400, "Field 'currency' is required");
  }

  const form: Record<string, string> = {
    amount: String(amount),
    currency: currency.toLowerCase(),
    "automatic_payment_methods[enabled]": "true",
  };

  if (description && typeof description === "string") {
    form.description = description;
  }

  if (receipt_email && typeof receipt_email === "string") {
    form.receipt_email = receipt_email;
  }

  if (metadata && typeof metadata === "object") {
    for (const [key, value] of Object.entries(metadata)) {
      if (typeof value === "string") {
        form[`metadata[${key}]`] = value;
      }
    }
  }

  const stripeResponse = await fetchJson<{
    id: string;
    client_secret?: string;
    amount: number;
    currency: string;
    status: string;
  }>(
    "https://api.stripe.com/v1/payment_intents",
    {
      method: "POST",
      headers: {
        authorization: `Bearer ${env.STRIPE_SECRET_KEY}`,
        "content-type": "application/x-www-form-urlencoded",
      },
      body: toFormUrlEncoded(form),
    },
    "Stripe request failed"
  );

  return jsonResponse({
    success: true,
    provider: "stripe",
    payment_intent: {
      id: stripeResponse.id,
      client_secret: stripeResponse.client_secret,
      amount: stripeResponse.amount,
      currency: stripeResponse.currency,
      status: stripeResponse.status,
    },
  });
};

