const router = async (request: Request, env: Env): Promise<Response> => {
  const url = new URL(request.url);

  if (request.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers: getCorsHeaders(env),
    });
  }

  if (url.pathname === "/health" && request.method === "GET") {
    return handleHealth(env);
  }

  if (url.pathname === "/api/email/send" && request.method === "POST") {
    return handleSendEmail(request, env);
  }

  if (url.pathname === "/api/payments/create-intent" && request.method === "POST") {
    return handleCreatePaymentIntent(request, env);
  }

  throw new HttpError(404, "Not Found");
};

